parameters.start:
={{ 
  (() => {
    const info = $('Parse AI Data').item.json?.keyInformation || [];
    const dateObj = info.find(item => {
      const label = item.label ? item.label.toLowerCase() : '';
      return (label.includes("date") || label.includes("period") || label.includes("due")) && !label.includes("cost") && !label.includes("amount");
    });

    if (dateObj && dateObj.value) {
      const match = dateObj.value.match(/\d{4}-\d{2}-\d{2}/);
      if (match) return match[0] + "T09:00:00";
      try {
        const parsedDate = new Date(dateObj.value);
        if (!isNaN(parsedDate.getTime())) {
          return parsedDate.toISOString().split('T')[0] + "T09:00:00";
        }
      } catch(e) {}
    }
    return $now.plus({ days: 1 }).toFormat('yyyy-MM-dd') + "T09:00:00";
  })()
}}

